SourceCode.Declaration:
/// <summary>
/// JSON contract for <c>SIMSStartSqlExecutionService.executeSql</c>.
/// Provide either <c>LineRecId</c> (catalog SQL line) or ad-hoc <c>SqlScript</c> when enabled.
/// </summary>
[DataContractAttribute]
public class SIMSStartSqlExecuteRequestContract
{
    RefRecId    lineRecId;
    str         sqlScript;
    str         correlationId;
}

Method.Source:
[DataMemberAttribute('LineRecId')]
public RefRecId parmLineRecId(RefRecId _lineRecId = lineRecId)
{
    lineRecId = _lineRecId;
    return lineRecId;
}

[DataMemberAttribute('SqlScript')]
public str parmSqlScript(str _sqlScript = sqlScript)
{
    sqlScript = _sqlScript;
    return sqlScript;
}

[DataMemberAttribute('CorrelationId')]
public str parmCorrelationId(str _correlationId = correlationId)
{
    correlationId = _correlationId;
    return correlationId;
}
